const fs = require('fs');
const path = require('path');

/**
 * Rekursiv alle .test.js-Dateien laden
 * @param {string} dir - Startverzeichnis
 */
function loadTestsRecursively(dir) {
  const entries = fs.readdirSync(dir, { withFileTypes: true });

  for (const entry of entries) {
    const fullPath = path.join(dir, entry.name);

    if (entry.isDirectory()) {
      loadTestsRecursively(fullPath);
    } else if (entry.isFile() && entry.name.endsWith('.test.js')) {
      require(fullPath);
    }
  }
}

// Starte in allen relevanten Testverzeichnissen
const testRoot = path.resolve(__dirname, '..');
['unit', 'integration', 'functional'].forEach(subdir => {
  const fullPath = path.join(testRoot, subdir);
  if (fs.existsSync(fullPath)) {
    loadTestsRecursively(fullPath);
  }
});